import { useEffect, useState } from "react";

function App() {
  const [loading, setLoading] = useState(true);
  const [coins, setCoins] = useState([]);
  const [coinValue, setCoinValue] = useState(0);
  const [dollar, setDollar] = useState("");
  useEffect(() => {
    fetch("https://api.coinpaprika.com/v1/tickers?limit=10")
      .then((response) => response.json())
      .then((json) => {
        setCoins(json);
        setLoading(false);
      });
  }, []);
  function onSelect(event) {
    console.log(event);
    setCoinValue(event.target.value);
  }
  function onChangeDollar(event) {
    setDollar(event.target.value);
  }

  return (
    <div>
      <h1>The Coins!{loading ? "" : `(${coins.length})`}</h1>
      {loading ? (
        <strong>Loading...</strong>
      ) : (
        <select id="selectBox" onChange={onSelect}>
          <option>Select coin</option>
          {coins.map((coin) => (
            <option
              key={coin.id}
              id={coin.symbol}
              value={coin.quotes.USD.price}
            >
              {coin.name}({coin.symbol}): ${coin.quotes.USD.price.toFixed(8)}{" "}
              USD
            </option>
          ))}
        </select>
      )}

      <div>
        <label htmlFor="dollar">If you have $</label>
        <input
          value={dollar}
          id="dollar"
          onChange={onChangeDollar}
          type="number"
          placeholder="type"
        />
        <h3>You can buy {dollar / coinValue} coins</h3>
      </div>
    </div>
  );
}

export default App;
